package com.taskmind.backend.specbreakdown.infrastructure.persistence.jpa;
import com.taskmind.backend.specbreakdown.domain.model.SpecBreakdownDraft; import com.taskmind.backend.specbreakdown.domain.repository.SpecBreakdownDraftRepository; import java.util.*; import org.springframework.stereotype.Repository;
@Repository class JpaSpecBreakdownDraftRepository implements SpecBreakdownDraftRepository { private final SpringDataSpecBreakdownDraftRepository repo; JpaSpecBreakdownDraftRepository(SpringDataSpecBreakdownDraftRepository repo){this.repo=repo;} public SpecBreakdownDraft save(SpecBreakdownDraft d){return repo.saveAndFlush(SpecBreakdownDraftJpaEntity.from(d)).toDomain();} public Optional<SpecBreakdownDraft> findById(UUID id){return repo.findById(id).map(SpecBreakdownDraftJpaEntity::toDomain);} public List<SpecBreakdownDraft> findByProjectId(UUID projectId){return repo.findByProjectIdOrderByUpdatedAtDesc(projectId).stream().map(SpecBreakdownDraftJpaEntity::toDomain).toList();}}
